INSERT INTO articles (id, title, slug, lead, content, category_id, status, published_at, views) VALUES
(
  'a5000000-0000-4000-a000-000000000001',
  'В Ингушетии высажено 73 тысячи саженцев ясеня в рамках нацпроекта «Экологическое благополучие»',
  'v-ingushetii-vysazheno-73-tys-sazhencev-yasenya',
  'В лесном фонде региона прошли масштабные мероприятия по искусственному лесовосстановлению на площади 35 гектаров.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В лесном фонде Ингушетии прошли масштабные мероприятия по искусственному лесовосстановлению. На площади 35 гектаров высажено 73 тысячи саженцев ясеня обыкновенного. Работы выполнены в рамках государственного задания и федерального проекта «Сохранение лесов» национального проекта «Экологическое благополучие»."}]},{"type":"paragraph","content":[{"type":"text","text":"Посадка проведена на территориях двух районов республики: 21 гектар в Сунженском районе и 14 гектаров в Назрановском районе. В ходе работ использован посадочный материал как с открытой, так и с закрытой корневой системой, что помогает деревьям лучше приживаться и быстрее расти."}]},{"type":"paragraph","content":[{"type":"text","text":"Мероприятия реализованы силами сотрудников Сунженского и Назрановского лесопожарных центров."}]},{"type":"paragraph","content":[{"type":"text","text":"Министр природных ресурсов и экологии Ингушетии Микаил Мизиев подчеркнул, что высадка ясеня является частью системной работы по восстановлению лесного фонда региона. По его словам, лес — основа экологической системы, от него напрямую зависит качество жизни людей, состояние почв и водных ресурсов."}]},{"type":"paragraph","content":[{"type":"text","text":"Министр отметил, что сегодня в республике не просто увеличивают площадь лесов, а создают устойчивую природную среду, которая лучше справляется с климатическими и другими негативными воздействиями. Напомним, 2026 год объявлен Главой Ингушетии Годом экологии."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-09T09:00:00Z',
  47
),
(
  'a5000000-0000-4000-a000-000000000002',
  'В Ингушетии официально стартовал пожароопасный сезон 2026 года',
  'v-ingushetii-startoval-pozharoopasnyj-sezon-2026',
  'Пожароопасный период продлится до 30 ноября. Усилено информационное взаимодействие и работа диспетчерских служб.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Республике Ингушетия официально начался пожароопасный сезон 2026 года. Об этом сообщили в Министерстве природных ресурсов и экологии региона."}]},{"type":"paragraph","content":[{"type":"text","text":"Пожароопасным сезоном считается период со времени схода снежного покрова до наступления устойчивой дождливой осенней погоды или выпадения снега. В Ингушетии этот период продлится до 30 ноября."}]},{"type":"paragraph","content":[{"type":"text","text":"В целях обеспечения полного и своевременного информационного обмена сведениями о лесных пожарах на землях лесного фонда усилена работа пункта диспетчерского управления. Специалисты готовы оперативно реагировать на любые возгорания и координировать действия служб."}]},{"type":"paragraph","content":[{"type":"text","text":"Минприроды Ингушетии призывает жителей и гостей республики соблюдать правила пожарной безопасности в лесах, не разводить костры в сухую погоду и не оставлять непотушенные источники огня. Большинство лесных пожаров происходит по вине человека, поэтому внимательность каждого имеет критическое значение."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-09T10:30:00Z',
  38
),
(
  'a5000000-0000-4000-a000-000000000003',
  'В Ингушетии в 2026 году проведут комплексный лесопатологический мониторинг',
  'v-ingushetii-kompleks-rabot-po-lesopatologicheskomu-monitoringu-2026',
  'Запланированы наблюдения на 66 пунктах постоянного мониторинга и детальное обследование лесов на площади 2650 гектаров.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В 2026 году в Ингушетии будет реализован комплекс мероприятий по государственному лесопатологическому мониторингу, направленный на сохранение и улучшение состояния лесного фонда региона."}]},{"type":"paragraph","content":[{"type":"text","text":"Подготовка к полевому сезону завершена, специалисты филиала ФБУ «Рослесозащита» — «Центр защиты леса Чеченской Республики» готовы приступить к выполнению всех запланированных работ. В течение года предусмотрено проведение регулярных наземных наблюдений за санитарным и лесопатологическим состоянием лесов на 66 пунктах постоянного мониторинга."}]},{"type":"paragraph","content":[{"type":"text","text":"Параллельно будут организованы выборочные наблюдения за популяциями вредных организмов на площади 655,9 гектара. Значительный объём работ запланирован в части детального обследования лесов: выборочные наземные наблюдения (лесопатологическая таксация) охватят территорию площадью 2650 гектаров."}]},{"type":"paragraph","content":[{"type":"text","text":"Эти мероприятия позволят своевременно выявлять изменения состояния лесных насаждений и оценивать возможные риски. При необходимости будет проведена инвентаризация очагов вредных организмов, что обеспечит оперативное реагирование и принятие мер по их локализации."}]},{"type":"paragraph","content":[{"type":"text","text":"Все работы направлены на повышение устойчивости лесных экосистем Ингушетии. К выполнению полевых работ специалисты приступят с началом вегетационного периода лесных растений."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-09T08:00:00Z',
  29
),
(
  'a5000000-0000-4000-a000-000000000004',
  'Спортсмены Ингушетии завоевали восемь медалей на Первенстве России по всестилевому карате',
  'sportsmeny-ingushetii-8-medalej-pervenstvo-rossii-karate',
  'С 1 по 7 апреля в Орле прошли соревнования среди спортсменов 14-20 лет, в которых приняли участие около 2500 человек из 66 регионов страны.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"С 1 по 7 апреля 2026 года в городе Орёл прошло Первенство России по всестилевому карате среди спортсменов 14-20 лет. В соревнованиях приняли участие около 2500 человек, представлявших 66 регионов страны."}]},{"type":"paragraph","content":[{"type":"text","text":"Несмотря на серьёзную конкуренцию, сборная команда Республики Ингушетия завоевала четыре золотые, одну серебряную и три бронзовые медали — всего восемь наград."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Золотые медали"}]},{"type":"paragraph","content":[{"type":"text","text":"Золото завоевали Шахмурзиев Абдул-Малик (16-17 лет, 85 кг), Эльджаркиев Адам (16-17 лет, 90 кг), Цечоев Давид (14-15 лет, 64 кг) и Гагиев Килар (14-15 лет, 57 кг)."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Серебро и бронза"}]},{"type":"paragraph","content":[{"type":"text","text":"Серебряная медаль в возрасте 16-17 лет в категории до 76 кг досталась Шаухалову Ахмеду. Бронзовые медали завоевали Шаухалов Илез (14-15 лет, 51 кг), Накастхоев Адам (18-20 лет, 85 кг) и Тамбиев Адам (14-15 лет, 76 кг)."}]},{"type":"paragraph","content":[{"type":"text","text":"Подготовкой ингушских спортсменов занимались тренеры Абдул-Азит Шаухалов, Исмаил Рассумов, Джабраил Костоев, Исмаил Илиев и Иса Котиев."}]}]}',
  'c1000000-0000-4000-a000-000000000005',
  'published',
  '2026-04-08T16:00:00Z',
  112
),
(
  'a5000000-0000-4000-a000-000000000005',
  'Сборная Ингушетии по шахбоксу завоевала шесть медалей на Первенстве России',
  'sbornaya-ingushetii-shakhboks-shest-medalej-pervenstvo-rossii',
  'Четыре спортсмена из республики получили путёвки на Первенство Европы в Турции, которое пройдёт с 27 апреля по 3 мая.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Москве прошли Чемпионат и Первенство России по шахбоксу — уникальному виду спорта, сочетающему шахматы и бокс. Сборная команда Республики Ингушетия продемонстрировала высочайший уровень подготовки, вернувшись с внушительным результатом — шестью медалями Первенства."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Золотые медали"}]},{"type":"paragraph","content":[{"type":"text","text":"Илез Баркинхоев одержал триумфальную победу среди юниоров 16-17 лет в весовой категории до 60 кг, завоевав золотую медаль. В категории юношей 12-13 лет Магомед Бопхоев стал победителем в весе до 50 кг, а Умар Цуроев добавил ещё одно золото в копилку команды, став лучшим в категории до 65 кг."}]},{"type":"paragraph","content":[{"type":"text","text":"Амир Аушев выиграл Первенство России среди самых юных участников 10-11 лет в весе до 37 кг, показав выдающуюся технику."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Серебро и бронза"}]},{"type":"paragraph","content":[{"type":"text","text":"К золотым триумфам добавились серебряная награда Абдул-Карима Аушева (12-13 лет, до 50 кг) и бронза Умара Баркинхоева (12-13 лет, до 55 кг)."}]},{"type":"paragraph","content":[{"type":"text","text":"Все четыре победителя Первенства России получили право представлять страну на предстоящем Первенстве Европы, которое состоится в Турции с 27 апреля по 3 мая 2026 года."}]}]}',
  'c1000000-0000-4000-a000-000000000005',
  'published',
  '2026-04-08T14:00:00Z',
  89
),
(
  'a5000000-0000-4000-a000-000000000006',
  'Ислам Халухаев завоевал две медали на Чемпионате России по армрестлингу и путёвку в Индию',
  'islam-halukhaev-dve-medali-chempionat-rossii-armrestling',
  'Ингушский спортсмен выполнил норматив мастера спорта России и поедет на Чемпионат мира.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В городе Орёл завершился Чемпионат России по армрестлингу среди спортсменов с поражением опорно-двигательного аппарата. Соревнования объединили 179 атлетов из 34 регионов страны."}]},{"type":"paragraph","content":[{"type":"text","text":"Представитель сборной Ингушетии Ислам Халухаев завоевал на этих соревнованиях две серебряные медали в весовой категории до 70 килограммов — как в борьбе правой, так и левой рукой."}]},{"type":"paragraph","content":[{"type":"text","text":"Этот результат позволил ингушскому спортсмену выполнить норматив мастера спорта России и получить путёвку на предстоящий Чемпионат мира, который состоится в Индии."}]},{"type":"paragraph","content":[{"type":"text","text":"Успех Ислама Халухаева — ещё одно подтверждение высокого уровня подготовки ингушских паралимпийских спортсменов и результат системной работы Министерства спорта республики по развитию адаптивного спорта."}]}]}',
  'c1000000-0000-4000-a000-000000000005',
  'published',
  '2026-04-07T18:00:00Z',
  76
);

